def _starburst_dataset_to_nested(
    starburst_dataset: StarburstDataset,
) -> StarburstDatasetNested:
    """Convert flat StarburstDataset to nested format."""
    attrs = StarburstDatasetAttributes()
    _populate_starburst_dataset_attrs(attrs, starburst_dataset)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        starburst_dataset,
        _STARBURST_DATASET_REL_FIELDS,
        StarburstDatasetRelationshipAttributes,
    )
    return StarburstDatasetNested(
        guid=starburst_dataset.guid,
        type_name=starburst_dataset.type_name,
        status=starburst_dataset.status,
        version=starburst_dataset.version,
        create_time=starburst_dataset.create_time,
        update_time=starburst_dataset.update_time,
        created_by=starburst_dataset.created_by,
        updated_by=starburst_dataset.updated_by,
        classifications=starburst_dataset.classifications,
        classification_names=starburst_dataset.classification_names,
        meanings=starburst_dataset.meanings,
        labels=starburst_dataset.labels,
        business_attributes=starburst_dataset.business_attributes,
        custom_attributes=starburst_dataset.custom_attributes,
        pending_tasks=starburst_dataset.pending_tasks,
        proxy=starburst_dataset.proxy,
        is_incomplete=starburst_dataset.is_incomplete,
        provenance_type=starburst_dataset.provenance_type,
        home_id=starburst_dataset.home_id,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


def _starburst_dataset_from_nested(nested: StarburstDatasetNested) -> StarburstDataset:
    """Convert nested format to flat StarburstDataset."""
    attrs = (
        nested.attributes
        if nested.attributes is not UNSET
        else StarburstDatasetAttributes()
    )
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _STARBURST_DATASET_REL_FIELDS,
        StarburstDatasetRelationshipAttributes,
    )
    return StarburstDataset(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        meanings=nested.meanings,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        **_extract_starburst_dataset_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _starburst_dataset_to_nested_bytes(
    starburst_dataset: StarburstDataset, serde: Serde
) -> bytes:
    """Convert flat StarburstDataset to nested JSON bytes."""
    return serde.encode(_starburst_dataset_to_nested(starburst_dataset))


def _starburst_dataset_from_nested_bytes(data: bytes, serde: Serde) -> StarburstDataset:
    """Convert nested JSON bytes to flat StarburstDataset."""
    nested = serde.decode(data, StarburstDatasetNested)
    return _starburst_dataset_from_nested(nested)


